-- Independent Contractor Agreement (California)
INSERT INTO contract_templates (
  contract_type,
  jurisdiction,
  version,
  title,
  preamble,
  recitals,
  clauses,
  signature_block,
  placeholders,
  is_active,
  metadata
) VALUES (
  'independent_contractor',
  'us_california',
  1,
  'Independent Contractor Agreement (California)',
  'This Independent Contractor Agreement (the "Agreement") is entered into as of {{effective_date}} (the "Effective Date"), by and between {{party_a_company}}, with an address at {{party_a_address}} ("Client"), and {{party_b_company}}, with an address at {{party_b_address}} ("Contractor"). Client and Contractor may be referred to individually as a "Party" and collectively as the "Parties".',
  'WHEREAS, Client desires to retain Contractor to perform certain services described in this Agreement; and
WHEREAS, Contractor represents that Contractor has the expertise, resources, and ability to perform such services;
NOW, THEREFORE, in consideration of the mutual covenants and promises contained herein, the Parties agree as follows:',
  '[{"id":"services","title":"1. SERVICES","content":"1.1 Services. Contractor shall perform the services described in {{services_description}} (the \"Services\") in a professional and workmanlike manner, consistent with generally accepted industry standards.\n\n1.2 Deliverables; Schedule. Any deliverables, milestones, deadlines, and acceptance criteria shall be as specified in {{services_description}} or as otherwise agreed in writing by the Parties.\n\n1.3 Place and Manner of Performance. Contractor will determine the method, details, and means of performing the Services; provided that Contractor shall reasonably cooperate with Client’s operational, security, and onsite policies when accessing Client’s facilities, systems, or personnel.\n\n1.4 Changes. Client may request changes to the scope of Services. Any material change affecting scope, timeline, or compensation must be agreed to in writing by both Parties.\n\n1.5 No Authority. Contractor has no authority to bind Client, incur obligations on Client’s behalf, or make representations as an agent of Client unless expressly authorized in a writing signed by Client.","type":"standard","order":1},{"id":"compensation","title":"2. COMPENSATION; INVOICING; EXPENSES","content":"2.1 Fees. As full consideration for the Services, Client shall pay Contractor as follows: (a) a total fee of {{payment_amount}} and/or (b) an hourly rate of {{hourly_rate}}, as applicable to the Services described in {{services_description}}.\n\n2.2 Invoicing and Payment Timing. Contractor shall invoice Client in accordance with the invoicing schedule stated in {{services_description}}. Unless otherwise stated in {{services_description}}, Client shall pay undisputed amounts within a commercially reasonable time after receipt of a proper invoice.\n\n2.3 Expenses. Unless expressly authorized in advance in writing by Client, Contractor is responsible for all expenses incurred in performing the Services. Any pre-approved reimbursable expenses must be supported by reasonable documentation.\n\n2.4 Taxes. Contractor is solely responsible for all federal, state, and local taxes, assessments, and other governmental charges arising from compensation paid under this Agreement, including without limitation income tax and self-employment tax. Client will not withhold or pay payroll taxes for Contractor.\n\n2.5 No Other Benefits. Contractor acknowledges that Contractor is not eligible for and waives any claim to Client-provided benefits, including without limitation workers’ compensation (except as required by law), unemployment insurance, disability insurance, vacation, sick leave, retirement benefits, or health benefits.","type":"standard","order":2},{"id":"independent_contractor_status_ab5","title":"3. INDEPENDENT CONTRACTOR STATUS; AB 5 / LABOR CODE COMPLIANCE","content":"3.1 Independent Contractor. Contractor is an independent contractor and not an employee, partner, joint venturer, agent, or representative of Client. Contractor shall control the manner and means of performing the Services, subject only to the requirements of this Agreement and any written specifications.\n\n3.2 No Employment Relationship. Nothing in this Agreement shall be construed to create an employment relationship. Contractor shall not represent that Contractor is an employee of Client.\n\n3.3 California Classification Compliance (AB 5). The Parties intend that Contractor be properly classified as an independent contractor under applicable California law, including the California Labor Code and related statutes and case law. Contractor represents and warrants that Contractor meets applicable requirements for independent contractor status, including, to the extent applicable, that: (a) Contractor is free from Client’s control and direction in connection with performance of the Services, both under this Agreement and in fact; (b) Contractor performs the Services outside the usual course of Client’s business or otherwise qualifies under an applicable statutory exemption; and (c) Contractor is customarily engaged in an independently established trade, occupation, or business of the same nature as the Services.\n\n3.4 Contractor’s Business. Contractor is responsible for providing tools, equipment, and materials necessary to perform the Services (except as expressly provided by Client), maintaining any required business licenses and permits, and operating Contractor’s business in compliance with law.\n\n3.5 Non-Exclusivity. Unless otherwise stated in {{services_description}}, Contractor may perform services for others during the Term, provided such services do not materially interfere with Contractor’s performance of the Services or breach this Agreement.","type":"standard","order":3},{"id":"term_termination","title":"4. TERM; TERMINATION; SUSPENSION","content":"4.1 Term. This Agreement begins on the Effective Date and continues until {{expiration_date}}, unless earlier terminated in accordance with this Section 4 (the \"Term\"). If {{expiration_date}} is not applicable, the Term shall continue until completion of the Services, unless earlier terminated as provided herein.\n\n4.2 Termination for Convenience. Either Party may terminate this Agreement for any reason upon written notice to the other Party at least {{notice_period}} days prior to the effective termination date.\n\n4.3 Termination for Cause. Either Party may terminate this Agreement immediately upon written notice if the other Party: (a) materially breaches this Agreement and fails to cure such breach within a reasonable time after receiving written notice specifying the breach; (b) becomes insolvent, makes a general assignment for the benefit of creditors, or becomes subject to bankruptcy or receivership proceedings; or (c) engages in fraud, willful misconduct, or unlawful conduct in connection with this Agreement.\n\n4.4 Effect of Termination. Upon termination: (a) Contractor shall promptly stop work except as necessary to wind down; (b) Contractor shall deliver to Client all Client property and, to the extent applicable, Work Product (defined below) created through the termination date; and (c) Client shall pay Contractor for Services properly performed and accepted through the termination effective date, subject to Client’s rights to withhold amounts for nonconforming work, offsets, or other remedies.\n\n4.5 Survival. Sections intended by their nature to survive termination shall survive, including without limitation Sections 5 (Intellectual Property), 6 (Confidentiality), 7 (Representations and Warranties), 8 (Indemnification), 9 (Insurance, if applicable), and 10 (General Provisions).","type":"standard","order":4},{"id":"intellectual_property","title":"5. INTELLECTUAL PROPERTY; WORK PRODUCT","content":"5.1 Definitions. \"Work Product\" means all deliverables, work product, inventions, discoveries, developments, designs, works of authorship, documentation, reports, analyses, software (including source code and object code), data compilations, and other materials that are conceived, created, developed, or reduced to practice by Contractor (alone or with others) in connection with performing the Services.\n\n5.2 Ownership; Assignment. To the fullest extent permitted by law, Client shall own all right, title, and interest in and to the Work Product. Contractor hereby irrevocably assigns (and agrees to assign) to Client all right, title, and interest worldwide in and to the Work Product, including all intellectual property rights therein.\n\n5.3 Further Assurances. Contractor shall execute and deliver such documents and take such actions as Client may reasonably request to perfect, maintain, enforce, or evidence Client’s rights in the Work Product.\n\n5.4 Contractor Background Technology. \"Background Technology\" means technology, tools, code, templates, methodologies, know-how, and materials owned or developed by Contractor outside the scope of this Agreement and not created specifically for Client. Contractor retains all rights in Contractor’s Background Technology. To the extent Contractor incorporates any Background Technology into the Work Product, Contractor grants to Client a perpetual, irrevocable, worldwide, royalty-free, fully paid-up, transferable (including to Client’s successors and assigns), and sublicensable license to use, reproduce, modify, distribute, perform, display, make, have made, sell, offer for sale, import, and otherwise exploit such Background Technology as part of, or in connection with, the Work Product.\n\n5.5 Moral Rights Waiver. To the extent permitted by applicable law, Contractor waives and agrees not to assert any \"moral rights\" or similar rights in the Work Product.\n\n5.6 No Restriction on Lawful Competition. Nothing in this Agreement is intended to, or shall, prohibit Contractor from engaging in any lawful profession, trade, or business, or from working for others, consistent with California Business and Professions Code section 16600 and related law.","type":"negotiable","order":5},{"id":"confidentiality","title":"6. CONFIDENTIALITY; TRADE SECRETS (CUTSA); DATA PROTECTION (CCPA)","content":"6.1 Confidential Information. \"Confidential Information\" means any non-public information disclosed by or on behalf of Client to Contractor (whether before or after the Effective Date), in any form, that is designated as confidential or that reasonably should be understood to be confidential given the nature of the information and the circumstances of disclosure. Confidential Information includes without limitation business, financial, marketing, pricing, customer, vendor, product, technical, security, and roadmap information; inventions and designs; and information that constitutes a \"trade secret\" under the California Uniform Trade Secrets Act (California Civil Code section 3426 et seq.) (\"CUTSA\").\n\n6.2 Exclusions. Confidential Information does not include information that Contractor can demonstrate by contemporaneous written records: (a) is or becomes publicly available through no breach of this Agreement; (b) was known to Contractor without restriction before receipt from Client; (c) is rightfully received from a third party without breach of any obligation of confidentiality; or (d) is independently developed by Contractor without use of or reference to Client’s Confidential Information.\n\n6.3 Confidentiality Obligations. Contractor shall: (a) use Confidential Information solely to perform the Services; (b) protect Confidential Information using at least the same degree of care Contractor uses to protect its own confidential information of similar importance, and no less than reasonable care; (c) not disclose Confidential Information to any third party except to Contractor’s personnel or subcontractors (if any) who have a need to know and are bound by confidentiality obligations at least as protective as this Agreement; and (d) promptly notify Client of any suspected or actual unauthorized access, use, or disclosure of Confidential Information.\n\n6.4 Return/Destruction. Upon Client’s request or upon termination of this Agreement, Contractor shall promptly return or destroy (at Client’s election) all Confidential Information, including copies, extracts, and summaries, except that Contractor may retain one archival copy solely for legal compliance purposes, subject to ongoing confidentiality obligations.\n\n6.5 Compelled Disclosure. If Contractor is required by law, regulation, or court order to disclose any Confidential Information, Contractor shall (to the extent legally permitted) provide Client prompt written notice and reasonably cooperate with Client’s efforts to seek a protective order or other appropriate remedy. Contractor shall disclose only the portion legally required.\n\n6.6 Injunctive Relief. Contractor acknowledges that unauthorized disclosure or use of Confidential Information may cause irreparable harm. Client is entitled to seek injunctive relief, in addition to any other remedies, without the necessity of posting bond to the extent permitted by law.\n\n6.7 Data Protection; CCPA. To the extent Contractor receives, accesses, stores, transmits, or otherwise processes personal information (as defined by the California Consumer Privacy Act of 2018, as amended, and its implementing regulations (\"CCPA\")) on behalf of Client in performing the Services, Contractor shall: (a) process such personal information solely for the business purpose(s) of performing the Services and not for any other purpose; (b) implement and maintain reasonable security procedures and practices appropriate to the nature of the information; (c) not \"sell\" or \"share\" (as those terms are defined under the CCPA) such personal information; (d) not retain, use, or disclose such personal information outside the direct business relationship between the Parties, except as permitted by the CCPA; and (e) notify Client without undue delay of any suspected or actual unauthorized access to or disclosure of such personal information.","type":"standard","order":6},{"id":"representations_warranties","title":"7. REPRESENTATIONS AND WARRANTIES","content":"7.1 Mutual Authority. Each Party represents and warrants that: (a) it has the full right, power, and authority to enter into and perform this Agreement; and (b) the person executing this Agreement on its behalf has been duly authorized to do so.\n\n7.2 Contractor Warranties. Contractor represents, warrants, and covenants that: (a) Contractor has the skill, experience, and resources necessary to perform the Services; (b) the Services will be performed in a professional and workmanlike manner and in accordance with applicable laws, rules, and regulations; (c) Contractor will obtain and maintain any licenses, permits, or approvals required to perform the Services; (d) to Contractor’s knowledge, the Work Product and Contractor’s performance will not infringe, misappropriate, or otherwise violate any intellectual property or proprietary rights of any third party; (e) Contractor will not introduce into Client’s systems any malicious code or knowingly compromise Client’s security; and (f) Contractor will comply with Client’s reasonable written security and confidentiality requirements provided to Contractor.\n\n7.3 No Conflict. Contractor represents that Contractor’s performance of the Services does not and will not violate any agreement or obligation between Contractor and any third party.\n\n7.4 Disclaimer. Except as expressly stated in this Agreement, neither Party makes any other warranties, whether express, implied, or statutory, including any implied warranties of merchantability, fitness for a particular purpose, or non-infringement, to the maximum extent permitted by law.","type":"standard","order":7},{"id":"indemnification","title":"8. INDEMNIFICATION; LIMITATION OF LIABILITY","content":"8.1 Contractor Indemnification. Contractor shall defend, indemnify, and hold harmless Client and its affiliates, and each of their respective officers, directors, employees, and agents, from and against any and all third-party claims, demands, actions, suits, proceedings, damages, liabilities, losses, judgments, penalties, fines, costs, and expenses (including reasonable attorneys’ fees) arising out of or related to: (a) bodily injury (including death) or damage to tangible property caused by Contractor or Contractor’s personnel in connection with the Services; (b) Contractor’s material breach of this Agreement; (c) allegations that the Work Product or Services infringe or misappropriate a third party’s intellectual property rights, to the extent caused by Contractor’s Work Product not based on Client materials or instructions; or (d) Contractor’s violation of applicable law.\n\n8.2 Client Indemnification. Client shall defend, indemnify, and hold harmless Contractor and its officers, directors, employees, and agents from and against any and all third-party claims, demands, actions, suits, proceedings, damages, liabilities, losses, judgments, penalties, fines, costs, and expenses (including reasonable attorneys’ fees) arising out of or related to Client-provided materials or instructions that infringe or misappropriate a third party’s intellectual property rights, provided Contractor used such materials or followed such instructions as authorized.\n\n8.3 Indemnification Procedure. The indemnified Party shall: (a) promptly notify the indemnifying Party of any claim (provided that failure to promptly notify will not relieve obligations except to the extent materially prejudiced); (b) allow the indemnifying Party to control the defense and settlement of the claim; and (c) reasonably cooperate. The indemnifying Party may not settle any claim in a manner that imposes non-monetary obligations or admissions of liability on the indemnified Party without the indemnified Party’s prior written consent.\n\n8.4 Limitation of Liability. To the maximum extent permitted by law, neither Party shall be liable to the other for any indirect, incidental, special, consequential, or punitive damages (including lost profits, loss of goodwill, or business interruption) arising out of or relating to this Agreement, whether in contract, tort, or otherwise, even if advised of the possibility of such damages. Nothing in this Agreement limits liability for fraud, willful misconduct, or liability that cannot be limited under applicable law.","type":"negotiable","order":8},{"id":"insurance","title":"9. INSURANCE (OPTIONAL)","content":"9.1 Coverage. If required by Client in writing, Contractor shall procure and maintain, at Contractor’s expense, insurance coverage appropriate to the Services and risks involved, which may include commercial general liability, professional liability/errors and omissions, cyber liability (if Contractor processes data), and automobile liability (if applicable).\n\n9.2 Proof of Insurance. Upon Client’s reasonable request, Contractor shall provide certificates of insurance evidencing the required coverage and limits.\n\n9.3 No Limitation. Insurance maintained by Contractor shall not be construed to limit Contractor’s obligations or liability under this Agreement.","type":"optional","order":9},{"id":"governing_law","title":"10. GOVERNING LAW; VENUE","content":"10.1 Governing Law. This Agreement shall be governed by and construed in accordance with the laws of {{governing_jurisdiction}}, without regard to conflict of laws principles.\n\n10.2 Venue. Subject to Section 10.3, the Parties agree that any action arising out of or relating to this Agreement shall be brought in the state or federal courts located in California, and each Party irrevocably submits to the personal jurisdiction of such courts.\n\n10.3 Equitable Relief. Notwithstanding the foregoing, a Party may seek temporary or preliminary injunctive relief in any court of competent jurisdiction to prevent irreparable harm.","type":"standard","order":10},{"id":"general_provisions","title":"11. GENERAL PROVISIONS","content":"11.1 Notices. Notices under this Agreement must be in writing and delivered by personal delivery, nationally recognized overnight courier, or email, to the addresses below (or to such other address as a Party may designate by notice). Notices to Client: {{party_a_email}} and {{party_a_address}}. Notices to Contractor: {{party_b_email}} and {{party_b_address}}.\n\n11.2 Assignment. Contractor may not assign or delegate this Agreement or any rights or obligations hereunder without Client’s prior written consent. Client may assign this Agreement in connection with a merger, acquisition, reorganization, or sale of substantially all assets upon written notice to Contractor.\n\n11.3 Subcontractors. Contractor may not use subcontractors to perform the Services without Client’s prior written consent. Contractor remains responsible for all acts and omissions of any approved subcontractors and shall ensure they are bound by written obligations consistent with this Agreement.\n\n11.4 Relationship of the Parties. The Parties are independent contracting parties. This Agreement does not create any partnership, joint venture, fiduciary relationship, or agency relationship.\n\n11.5 Compliance With Laws. Each Party shall comply with all applicable federal, state, and local laws and regulations in connection with its performance under this Agreement.\n\n11.6 Severability. If any provision of this Agreement is held invalid or unenforceable, the remaining provisions will remain in full force and effect, and the invalid or unenforceable provision will be enforced to the maximum extent permitted by law.\n\n11.7 Waiver. No waiver of any breach of any provision of this Agreement shall constitute a waiver of any prior, concurrent, or subsequent breach. Any waiver must be in writing and signed by the Party granting the waiver.\n\n11.8 Entire Agreement; Order of Precedence. This Agreement (including any exhibits or statements of work referenced in {{services_description}}, if any) constitutes the entire agreement between the Parties with respect to the subject matter and supersedes all prior or contemporaneous understandings. In the event of a conflict, this Agreement controls unless the Parties expressly agree otherwise in a signed writing.\n\n11.9 Amendments. Any amendment or modification to this Agreement must be in writing and signed by both Parties.\n\n11.10 Counterparts; Electronic Signatures. This Agreement may be executed in counterparts, each of which is deemed an original, and all of which together constitute one instrument. Signatures delivered electronically (including PDF or e-signature) shall be deemed effective.\n\n11.11 Headings. Headings are for convenience only and do not affect interpretation.\n\n11.12 Non-Disparagement; Non-Compete. The Parties acknowledge that, under California law (including California Business and Professions Code section 16600), contractual provisions that restrain lawful profession, trade, or business are generally void. Accordingly, nothing in this Agreement shall be interpreted as a non-compete or restraint on Contractor’s lawful work. Any non-disparagement obligations, if any, must comply with applicable law and are not intended to restrict legally protected speech or activities.\n\n11.13 Force Majeure. Neither Party shall be liable for delays or failures to perform due to causes beyond its reasonable control, including acts of God, natural disasters, labor disputes, war, terrorism, civil unrest, governmental actions, or failures of utilities or communications, provided the affected Party promptly notifies the other Party and uses reasonable efforts to resume performance.\n\n11.14 Interpretation. This Agreement shall be construed as jointly drafted, and no presumption shall arise favoring or disfavoring any Party by virtue of authorship.\n\n11.15 Signatures. The Parties agree that this Agreement is binding upon execution by authorized representatives.","type":"standard","order":11}]'::jsonb,
  'PARTY A (CLIENT):
{{party_a_company}}

