-- Freelance Service Agreement (California)
INSERT INTO contract_templates (
  contract_type,
  jurisdiction,
  version,
  title,
  preamble,
  recitals,
  clauses,
  signature_block,
  placeholders,
  is_active,
  metadata
) VALUES (
  'freelance_service',
  'us_california',
  1,
  'Freelance Service Agreement (California)',
  'This Freelance Service Agreement (the "Agreement") is entered into as of {{effective_date}} (the "Effective Date") by and between {{party_a_company}} ("Client"), with a principal address at {{party_a_address}}, and {{party_b_company}} ("Contractor"), with a principal address at {{party_b_address}}. Client and Contractor may be referred to herein individually as a "Party" and collectively as the "Parties."',
  'WHEREAS, Client desires to engage Contractor to perform certain freelance services for the project known as {{project_name}}; and
WHEREAS, Contractor represents that Contractor has the experience and ability to perform such services;
NOW, THEREFORE, in consideration of the mutual promises and covenants contained herein, the Parties agree as follows:',
  '[{"id":"definitions","title":"1. DEFINITIONS","content":"1.1 \"Deliverables\" means the items, work product, and other outputs to be provided by Contractor as described in Section 3 and/or otherwise agreed in writing by the Parties.\n\n1.2 \"Services\" means the professional services described in Section 2 and any additional services expressly agreed in a written change order or written statement of work signed or confirmed in writing by both Parties.\n\n1.3 \"Confidential Information\" has the meaning set forth in Section 11.\n\n1.4 \"Client Materials\" means any materials, content, data, software, documentation, trademarks, or other information provided by or on behalf of Client to Contractor.\n\n1.5 \"Contractor Materials\" means any tools, templates, pre-existing works, libraries, know-how, methods, processes, software, and other materials owned or controlled by Contractor prior to the Effective Date or developed by Contractor outside the scope of this Agreement without use of Client Confidential Information.\n\n1.6 \"Work Product\" means all Deliverables and other work product created by Contractor in the performance of the Services, excluding Contractor Materials.","type":"standard","order":1},{"id":"engagement_scope","title":"2. ENGAGEMENT; PROJECT SCOPE","content":"2.1 Engagement. Client retains Contractor, and Contractor accepts such engagement, to perform the Services for the project known as {{project_name}}.\n\n2.2 Scope of Services. Contractor shall perform the following Services: {{services_description}}.\n\n2.3 Out-of-Scope Items. Any tasks or deliverables not expressly included in the Services or Deliverables are excluded. If Client requests out-of-scope work, the Parties shall follow the change process in Section 5.\n\n2.4 Cooperation. Client shall provide timely access to Client Materials, information, personnel, and decisions reasonably necessary for Contractor to perform the Services. Contractor is not responsible for delays caused by Client’s failure to timely cooperate.","type":"standard","order":2},{"id":"deliverables_acceptance","title":"3. DELIVERABLES; REVIEW AND ACCEPTANCE","content":"3.1 Deliverables. Contractor shall provide the following Deliverables: {{deliverables}}.\n\n3.2 Delivery Method. Delivery shall be made in the format(s) and via the delivery method(s) agreed by the Parties in writing.\n\n3.3 Review and Acceptance. Client shall have a reasonable opportunity to review Deliverables upon receipt. Unless Client provides written notice of rejection describing material nonconformities within a reasonable time, the Deliverables will be deemed accepted. If Client timely rejects a Deliverable for material nonconformity, Contractor shall use commercially reasonable efforts to correct the nonconformity and re-deliver the Deliverable.\n\n3.4 Client Responsibilities for Accuracy. Client is responsible for reviewing Deliverables for accuracy, compliance, and suitability for Client’s intended use, including any legal or regulatory review applicable to Client’s business.","type":"standard","order":3},{"id":"timeline_milestones","title":"4. TIMELINE; MILESTONES","content":"4.1 Project Schedule. The Parties shall mutually agree in writing on any project schedule, milestones, or deadlines (a \"Project Schedule\").\n\n4.2 Dependencies. Any Project Schedule is contingent upon Client’s timely provision of required inputs, feedback, and approvals. Contractor will not be responsible for missed deadlines caused by Client delays, changes in scope, or events outside Contractor’s reasonable control.\n\n4.3 No Guaranteed Results. Contractor will perform the Services in a professional and workmanlike manner but does not guarantee any particular business, financial, marketing, or other outcome from the Services or Deliverables.","type":"standard","order":4},{"id":"changes","title":"5. CHANGES; CHANGE ORDERS","content":"5.1 Change Requests. Either Party may request changes to the Services, Deliverables, assumptions, or Project Schedule.\n\n5.2 Change Order Required. Any change must be documented in a written change order or written amendment describing (as applicable) the revised scope, Deliverables, timeline, and any fee adjustment. Contractor is not obligated to commence changed work until the change order is agreed in writing by both Parties.\n\n5.3 Effect on Fees and Timeline. Changes may require adjustments to fees, delivery dates, or other terms. Client acknowledges that requesting changes may extend timelines.","type":"standard","order":5},{"id":"payment_terms","title":"6. FEES; INVOICING; PAYMENT TERMS","content":"6.1 Fees. In consideration for the Services, Client shall pay Contractor {{payment_amount}}, unless otherwise agreed in a written change order.\n\n6.2 Deposit/Retainer. If applicable, Client shall pay a deposit/retainer of {{deposit_amount}}. Unless otherwise agreed in writing, the deposit/retainer is applied against the total fees.\n\n6.3 Invoicing. Contractor may invoice Client as agreed in writing by the Parties (including, as applicable, upon commencement, upon delivery of milestones, upon delivery of Deliverables, periodically, or upon completion).\n\n6.4 Payment Due Date. Client shall pay undisputed amounts within the time stated on Contractor’s invoice. Client shall notify Contractor in writing of any good-faith dispute regarding an invoice within a reasonable time after receipt, describing the basis for the dispute in reasonable detail, and shall timely pay any undisputed portion.\n\n6.5 Late Payments. Past-due undisputed amounts may accrue interest at the lesser of (a) the maximum rate permitted under California law or (b) the rate stated on the invoice, from the date due until paid.\n\n6.6 Taxes. Contractor is responsible for all taxes arising from amounts paid under this Agreement (except taxes on Client’s income). If any withholding is legally required, Client shall provide documentation of such withholding.\n\n6.7 No Contingent Fees Unless Agreed. Fees are not contingent on results unless expressly agreed in a separate written agreement signed by both Parties.","type":"standard","order":6},{"id":"revisions","title":"7. REVISIONS; CLIENT FEEDBACK","content":"7.1 Included Revisions. Unless the Parties expressly agree in writing to a specific number of revision rounds, reasonable revisions consistent with the agreed scope are included to address material alignment with the agreed requirements.\n\n7.2 Revision Limits. Revisions do not include (a) changes in scope, (b) new concepts or directions not previously approved, (c) changes requested due to Client-provided errors or late changes, or (d) substantial rework due to Client delays or failure to provide required information. Such items constitute out-of-scope work and are subject to Section 5.\n\n7.3 Timely Feedback. Client shall provide consolidated feedback in a timely manner. Delayed or piecemeal feedback may impact the Project Schedule.","type":"standard","order":7},{"id":"expenses","title":"8. EXPENSES; CLIENT-PROVIDED ACCOUNTS","content":"8.1 Expenses. Unless expressly authorized in writing by Client in advance, Contractor shall bear Contractor’s ordinary business expenses. Any pre-approved, reasonable, and necessary out-of-pocket expenses incurred for the benefit of the project shall be reimbursed by Client upon receipt of appropriate documentation.\n\n8.2 Third-Party Services. If the Services require third-party tools, hosting, licenses, subscriptions, or materials, Client is responsible for obtaining and maintaining such third-party products unless otherwise agreed in writing. Client is responsible for compliance with third-party terms.","type":"standard","order":8},{"id":"independent_contractor_ab5","title":"9. INDEPENDENT CONTRACTOR STATUS; CALIFORNIA COMPLIANCE (INCLUDING AB 5)","content":"9.1 Independent Contractor. Contractor is an independent contractor and not an employee, agent, joint venturer, or partner of Client. Contractor has no authority to bind Client.\n\n9.2 Control and Manner of Work. Contractor retains the right to control and direct the manner and means of performing the Services, subject to Client’s right to specify desired results, project requirements, and deadlines.\n\n9.3 No Benefits. Contractor is not eligible for, and waives any right to claim, any benefits from Client, including workers’ compensation (except as required by law), unemployment insurance, health insurance, paid leave, retirement benefits, or any other employee benefits.\n\n9.4 Taxes and Withholding. Contractor is solely responsible for all payroll taxes, self-employment taxes, and other taxes, withholdings, and reporting obligations arising from amounts paid under this Agreement.\n\n9.5 AB 5 / Worker Classification. The Parties intend and agree that Contractor will perform the Services as an independent contractor consistent with applicable California law, including California Labor Code and California’s worker-classification requirements (including AB 5 and any applicable exemptions or successor laws). Each Party agrees to cooperate in good faith to structure performance of the Services to comply with applicable law. Nothing in this Agreement is intended to, or shall be construed to, require either Party to violate applicable worker-classification laws.\n\n9.6 Equipment and Place of Work. Contractor will generally provide Contractor’s own equipment and tools and may perform the Services at locations determined by Contractor, unless the Parties agree otherwise in writing for specific tasks.\n\n9.7 Non-Exclusivity. Unless otherwise agreed in writing, Contractor may perform services for others during the Term, provided that Contractor complies with confidentiality obligations and avoids conflicts of interest.","type":"negotiable","order":9},{"id":"ip_ownership","title":"10. INTELLECTUAL PROPERTY; OWNERSHIP; LICENSES","content":"10.1 Client Ownership of Work Product Upon Payment. Subject to Section 10.2 and Contractor’s receipt of all amounts due under this Agreement, Contractor hereby assigns to Client all right, title, and interest in and to the Work Product (including all intellectual property rights therein) created specifically for Client under this Agreement.\n\n10.2 Contractor Materials. Contractor retains all right, title, and interest in and to Contractor Materials. To the extent any Contractor Materials are incorporated into the Deliverables, Contractor grants Client a non-exclusive, worldwide, perpetual, royalty-free license to use, reproduce, display, perform, distribute, and create derivative works of such Contractor Materials solely as embedded in or necessary to use the Deliverables for Client’s internal business purposes and any purposes expressly contemplated by the project, subject to full payment.\n\n10.3 Client Materials. Client retains all right, title, and interest in and to Client Materials. Client grants Contractor a limited, non-exclusive, non-transferable license to use Client Materials solely to perform the Services during the Term.\n\n10.4 Work Made for Hire; Assignment. To the extent any Work Product does not qualify as a “work made for hire” under applicable law, Contractor agrees that such Work Product is specially commissioned and hereby irrevocably assigns it to Client as provided in Section 10.1.\n\n10.5 Further Assurances. Contractor shall execute and deliver such documents and take such actions as Client may reasonably request to evidence, maintain, or enforce Client’s rights in the Work Product.\n\n10.6 Moral Rights. To the maximum extent permitted by applicable law, Contractor waives and agrees not to assert any “moral rights” or similar rights in the Work Product against Client or Client’s successors and assigns.\n\n10.7 Portfolio Use (If Allowed). Unless Client objects in writing, Contractor may include non-confidential excerpts or images of the Deliverables in Contractor’s portfolio solely to demonstrate Contractor’s work, provided that such use does not disclose Client Confidential Information or personal information and complies with any brand guidelines provided by Client.","type":"negotiable","order":10},{"id":"confidentiality_trade_secrets","title":"11. CONFIDENTIALITY; TRADE SECRETS (CUTSA)","content":"11.1 Confidential Information. \"Confidential Information\" means any non-public information disclosed by or on behalf of a Party (the \"Disclosing Party\") to the other Party (the \"Receiving Party\"), whether oral, written, electronic, visual, or otherwise, that is designated as confidential or that reasonably should be understood to be confidential given the nature of the information and the circumstances of disclosure, including business plans, customer information, pricing, product information, source code, designs, marketing strategies, and the terms of this Agreement.\n\n11.2 Exclusions. Confidential Information does not include information that the Receiving Party can demonstrate: (a) is or becomes publicly available through no breach of this Agreement; (b) was lawfully known by the Receiving Party without restriction before disclosure; (c) is lawfully received from a third party without breach of any obligation; or (d) is independently developed by the Receiving Party without use of or reference to the Disclosing Party’s Confidential Information.\n\n11.3 Use and Nondisclosure. The Receiving Party shall (a) use Confidential Information solely to perform or receive the Services and to exercise rights under this Agreement, (b) not disclose Confidential Information to any third party except as permitted herein, and (c) protect Confidential Information using at least reasonable care.\n\n11.4 Permitted Disclosures. The Receiving Party may disclose Confidential Information to its employees, contractors, and professional advisors who have a need to know and who are bound by confidentiality obligations at least as protective as those in this Agreement. The Receiving Party remains responsible for any breach by such persons.\n\n11.5 Compelled Disclosure. If the Receiving Party is required by law, regulation, or court order to disclose Confidential Information, it shall (to the extent legally permitted) provide prompt written notice to the Disclosing Party and reasonably cooperate with the Disclosing Party’s efforts to seek protective treatment.\n\n11.6 Return/Destruction. Upon request at any time, and in any event upon termination, the Receiving Party shall promptly return or destroy the Disclosing Party’s Confidential Information in its possession or control, except that the Receiving Party may retain copies as required for legal, regulatory, or bona fide backup and archival purposes, subject to continuing confidentiality obligations.\n\n11.7 Trade Secrets; Injunctive Relief. The Parties acknowledge that unauthorized use or disclosure of Confidential Information, including trade secrets as defined under the California Uniform Trade Secrets Act (California Civil Code section 3426 et seq.), may cause irreparable harm. The Disclosing Party is entitled to seek injunctive relief in addition to any other remedies available at law or equity.","type":"standard","order":11},{"id":"privacy_ccpa","title":"12. DATA PRIVACY; CCPA CONSIDERATIONS","content":"12.1 Applicability. To the extent Contractor receives, accesses, collects, stores, or otherwise processes personal information (as defined under applicable privacy laws, including the California Consumer Privacy Act and its regulations, as amended by the CPRA (collectively, \"CCPA\")) on behalf of Client in connection with the Services, this Section 12 applies.\n\n12.2 Processing Instructions and Purpose Limitation. Contractor shall process personal information only (a) for the limited and specified purposes of performing the Services, (b) in accordance with Client’s documented instructions as provided in writing, and (c) as permitted by applicable law.\n\n12.3 No Sale/Sharing. Contractor shall not sell or share personal information (as those terms are defined under CCPA) processed on behalf of Client.\n\n12.4 Confidentiality and Security. Contractor shall implement and maintain reasonable security procedures and practices appropriate to the nature of the personal information processed and shall restrict access to authorized persons.\n\n12.5 Subcontractors. Contractor shall not engage subcontractors to process personal information on behalf of Client without providing notice to Client and ensuring such subcontractors are bound by written terms no less protective than this Agreement with respect to such personal information.\n\n12.6 Assistance. To the extent applicable and reasonably requested by Client, Contractor shall provide reasonable assistance to Client to help Client respond to verified consumer requests, security incident inquiries, or regulatory requests related to personal information processed under this Agreement.\n\n12.7 Deletion/Return. Upon completion of the Services or upon Client’s written request, Contractor shall delete or return personal information processed on behalf of Client, except to the extent retention is required by law or for legitimate business purposes permitted by applicable law, subject to continuing confidentiality and security obligations.","type":"optional","order":12},{"id":"term_termination_cancellation","title":"13. TERM; TERMINATION; CANCELLATION","content":"13.1 Term. This Agreement begins on the Effective Date and continues until (a) completion and acceptance of the Deliverables and payment of all amounts due, or (b) {{expiration_date}}, whichever occurs first, unless earlier terminated under this Section 13.\n\n13.2 Termination for Convenience. Either Party may terminate this Agreement for convenience by providing written notice to the other Party at least {{notice_period}} days prior to the effective termination date.\n\n13.3 Termination for Cause. Either Party may terminate this Agreement immediately upon written notice if the other Party materially breaches this Agreement and fails to cure such breach within a reasonable time after receiving written notice describing the breach (except where cure is not possible).\n\n13.4 Effect of Termination; Payment. Upon termination, Client shall pay Contractor for (a) Services performed through the effective termination date, (b) any approved expenses incurred prior to termination, and (c) any non-cancellable commitments reasonably made in reliance on this Agreement with Client’s prior written approval.\n\n13.5 Work-in-Progress; Transition. Upon termination, Contractor shall, upon Client’s request and subject to Client’s payment of amounts due, provide Client with then-current work-in-progress and reasonable transition assistance.\n\n13.6 Cancellation of Project. If Client cancels the project after work has begun, the Parties agree that Contractor will have reserved capacity and incurred opportunity costs. Accordingly, amounts paid or due are nonrefundable to the maximum extent permitted by law for Services performed and commitments made, and any refund (if any) will be limited to unearned fees after accounting for work completed and non-cancellable costs.","type":"standard","order":13},{"id":"warranties_disclaimers","title":"14. WARRANTIES; DISCLAIMERS","content":"14.1 Contractor Warranty. Contractor warrants that the Services will be performed in a professional and workmanlike manner consistent with generally accepted industry standards.\n\n14.2 Client Warranty. Client represents and warrants that (a) Client has the right to provide Client Materials to Contractor, (b) Client Materials and Client instructions will not infringe or misappropriate third-party rights, and (c) Client will use Deliverables in compliance with applicable laws.\n\n14.3 Disclaimer. EXCEPT AS EXPRESSLY STATED IN THIS AGREEMENT, NEITHER PARTY MAKES ANY OTHER WARRANTIES, WHETHER EXPRESS, IMPLIED, STATUTORY, OR OTHERWISE, AND EACH PARTY DISCLAIMS ALL IMPLIED WARRANTIES, INCLUDING ANY IMPLIED WARRANTIES OF MERCHANTABILITY, FITNESS FOR A PARTICULAR PURPOSE, AND NON-INFRINGEMENT, TO THE MAXIMUM EXTENT PERMITTED BY APPLICABLE LAW.","type":"standard","order":14},{"id":"limitation_of_liability","title":"15. LIMITATION OF LIABILITY","content":"15.1 Limitation. TO THE MAXIMUM EXTENT PERMITTED BY LAW, IN NO EVENT SHALL EITHER PARTY BE LIABLE TO THE OTHER FOR ANY INDIRECT, INCIDENTAL, CONSEQUENTIAL, SPECIAL, EXEMPLARY, OR PUNITIVE DAMAGES, OR FOR ANY LOSS OF PROFITS, REVENUE, BUSINESS, OR GOODWILL, ARISING OUT OF OR RELATED TO THIS AGREEMENT, WHETHER IN CONTRACT, TORT (INCLUDING NEGLIGENCE), OR OTHERWISE, EVEN IF ADVISED OF THE POSSIBILITY OF SUCH DAMAGES.\n\n15.2 Cap. TO THE MAXIMUM EXTENT PERMITTED BY LAW, EACH PARTY’S TOTAL AGGREGATE LIABILITY ARISING OUT OF OR RELATED TO THIS AGREEMENT SHALL NOT EXCEED THE TOTAL AMOUNTS PAID OR PAYABLE BY CLIENT TO CONTRACTOR UNDER THIS AGREEMENT (WHICHEVER IS GREATER), WHICH AMOUNTS ARE CURRENTLY {{payment_amount}}.\n\n15.3 Exceptions. The limitations in this Section 15 do not apply to: (a) a Party’s breach of Section 11 (Confidentiality), (b) a Party’s gross negligence or willful misconduct, or (c) amounts that cannot be limited under applicable law.","type":"negotiable","order":15},{"id":"indemnification","title":"16. INDEMNIFICATION","content":"16.1 By Contractor. Contractor shall indemnify, defend, and hold harmless Client and its officers, directors, employees, and agents from and against any third-party claims, damages, liabilities, costs, and expenses (including reasonable attorneys’ fees) arising out of an allegation that the Deliverables, as delivered and used by Client as contemplated by this Agreement, infringe or misappropriate such third party’s intellectual property rights; provided that Client (a) promptly notifies Contractor in writing of the claim, (b) allows Contractor sole control of the defense and settlement (subject to Section 16.4), and (c) provides reasonable cooperation.\n\n16.2 Exclusions. Contractor’s indemnity obligations do not apply to claims to the extent arising from: (a) Client Materials; (b) Client’s modifications to Deliverables not made by Contractor; (c) Client’s use of Deliverables other than as contemplated by this Agreement; or (d) Client’s combination of Deliverables with products, services, or materials not provided by Contractor, if the claim would not have arisen but for such combination.\n\n16.3 By Client. Client shall indemnify, defend, and hold harmless Contractor and its officers, directors, employees, and agents from and against any third-party claims, damages, liabilities, costs, and expenses (including reasonable attorneys’ fees) arising out of or related to (a) Client Materials, or (b) Client’s use of the Deliverables in violation of applicable law or third-party rights.\n\n16.4 Settlement Restrictions. Neither Party may settle any claim requiring an admission of liability or wrongdoing by the other Party, or imposing non-monetary obligations on the other Party, without the other Party’s prior written consent (not to be unreasonably withheld).","type":"negotiable","order":16},{"id":"governing_law_venue","title":"17. GOVERNING LAW; VENUE","content":"17.1 Governing Law. This Agreement and any dispute arising out of or relating to it shall be governed by the laws of {{governing_jurisdiction}}, without regard to its conflict-of-laws principles.\n\n17.2 Venue; Jurisdiction. Subject to any mandatory requirements of applicable law, the Parties consent to the exclusive jurisdiction and venue of the state and federal courts located in the governing jurisdiction for any action arising out of or relating to this Agreement.\n\n17.3 Equitable Relief. Notwithstanding the foregoing, either Party may seek injunctive or other equitable relief in any court of competent jurisdiction to prevent actual or threatened misuse or disclosure of Confidential Information or infringement or misappropriation of intellectual property rights.","type":"standard","order":17},{"id":"notices","title":"18. NOTICES","content":"18.1 Form of Notice. All notices required or permitted under this Agreement must be in writing and will be deemed given when delivered by personal delivery, recognized overnight courier, or email (with confirmation of transmission) to the addresses below (or to such other address as a Party may designate by notice).\n\n18.2 Notice Addresses.\n\nIf to Client:\nName/Title: {{party_a_name}}, {{party_a_title}}\nCompany: {{party_a_company}}\nAddress: {{party_a_address}}\nEmail: {{party_a_email}}\n\nIf to Contractor:\nName/Title: {{party_b_name}}, {{party_b_title}}\nCompany: {{party_b_company}}\nAddress: {{party_b_address}}\nEmail: {{party_b_email}}","type":"standard","order":18},{"id":"general_provisions","title":"19. GENERAL PROVISIONS","content":"19.1 Entire Agreement. This Agreement (including any written change orders or written statements of work incorporated by reference) constitutes the entire agreement between the Parties regarding its subject matter and supersedes all prior or contemporaneous understandings, communications, and agreements.\n\n19.2 Amendments. Any amendment or modification must be in writing and signed or confirmed in writing by both Parties.\n\n19.3 Assignment. Neither Party may assign or transfer this Agreement without the prior written consent of the other Party, except that either Party may assign this Agreement in connection with a merger, acquisition, or sale of substantially all of its assets, provided that the assignee agrees in writing to be bound by this Agreement.\n\n19.4 Severability. If any provision of this Agreement is held invalid or unenforceable, the remaining provisions will remain in full force and effect, and the provision will be enforced to the maximum extent permitted by law consistent with the Parties’ intent.\n\n19.5 Waiver. No waiver of any breach will be deemed a waiver of any other or subsequent breach. Any waiver must be in writing.\n\n19.6 Force Majeure. Neither Party shall be liable for delays or failures to perform due to events beyond its reasonable control, provided that the affected Party gives prompt notice and uses commercially reasonable efforts to resume performance.\n\n19.7 Counterparts; Electronic Signatures. This Agreement may be executed in counterparts, each of which is deemed an original and all of which together constitute one instrument. Signatures transmitted electronically or via e-signature platform shall be deemed original.\n\n19.8 No Non-Competition Obligation. The Parties acknowledge that, under California law, post-employment and post-engagement non-compete restrictions are generally void. Nothing in this Agreement is intended to prohibit Contractor from engaging in Contractor’s lawful profession, trade, or business, subject to Contractor’s confidentiality obligations and protection of trade secrets.\n\n19.9 Interpretation. Headings are for convenience only and do not affect interpretation. The word \"including\" means \"including without limitation.\"","type":"standard","order":19}]'::jsonb,
