e","category":"dates","type":"date","required":true},{"id":"expiration_date","token":"{{expiration_date}}","label":"Expiration Date","description":"When the agreement ends (if applicable)","category":"dates","type":"date","required":false},{"id":"signature_date","token":"{{signature_date}}","label":"Signature Date","description":"Date of signing","category":"dates","type":"date","required":false},{"id":"governing_jurisdiction","token":"{{governing_jurisdiction}}","label":"Governing Jurisdiction","description":"State/country whose laws govern the agreement","category":"terms","type":"text","required":true},{"id":"notice_period","token":"{{notice_period}}","label":"Notice Period","description":"Days notice required for termination","category":"terms","type":"number","required":false},{"id":"deposit_amount","token":"{{deposit_amount}}","label":"Deposit Amount","description":"Upfront deposit or retainer","category":"financial","type":"currency","required":false},{"id":"hourly_rate","token":"{{hourly_rate}}","label":"Hourly Rate","description":"Rate per hour of work","category":"financial","type":"currency","required":false},{"id":"payment_amount","token":"{{payment_amount}}","label":"Payment Amount","description":"Total payment or fee amount","category":"financial","type":"currency","required":false},{"id":"deliverables","token":"{{deliverables}}","label":"Deliverables","description":"List of expected deliverables","category":"project","type":"textarea","required":false},{"id":"project_name","token":"{{project_name}}","label":"Project Name","description":"Name of the project or engagement","category":"project","type":"text","required":false},{"id":"services_description","token":"{{services_description}}","label":"Services Description","description":"Description of services to be provided","category":"project","type":"textarea","required":false}]'::jsonb,
