e","category":"dates","type":"date","required":true},{"id":"expiration_date","token":"{{expiration_date}}","label":"Expiration Date","description":"When the agreement ends (if applicable)","category":"dates","type":"date","required":false},{"id":"signature_date","token":"{{signature_date}}","label":"Signature Date","description":"Date of signing","category":"dates","type":"date","required":false},{"id":"governing_jurisdiction","token":"{{governing_jurisdiction}}","label":"Governing Jurisdiction","description":"State/country whose laws govern the agreement","category":"terms","type":"text","required":true},{"id":"confidentiality_period","token":"{{confidentiality_period}}","label":"Confidentiality Period","description":"Duration of confidentiality obligations (in years)","category":"terms","type":"number","required":false},{"id":"notice_period","token":"{{notice_period}}","label":"Notice Period","description":"Days notice required for termination","category":"terms","type":"number","required":false},{"id":"purpose","token":"{{purpose}}","label":"Purpose","description":"Purpose of the agreement or disclosure","category":"terms","type":"textarea","required":false}]'::jsonb,
